#include <iostream>
#include <string>
#include <vector>
#include <unordered_map>
#include <thread>
#include <mutex>
#include <boost/asio.hpp>

using boost::asio::ip::udp;

struct PlayerState {
    std::string id;
    float x, y, z;
    bool isShooting;
};

class GameServer {
public:
    GameServer(boost::asio::io_context& io_context, short port)
        : socket_(io_context, udp::endpoint(udp::v4(), port)) {
        receivePacket();
    }

    void sendPlayerStates() {
        std::lock_guard<std::mutex> lock(playerMutex_);
        for (const auto& player : players_) {
            // Send player state to all clients
            std::string message = "ID: " + player.id + " Pos: (" +
                                  std::to_string(player.x) + ", " +
                                  std::to_string(player.y) + ", " +
                                  std::to_string(player.z) + ") " +
                                  (player.isShooting ? "Shooting" : "Not Shooting");
            socket_.async_send_to(boost::asio::buffer(message), remote_endpoint_,
                                   [this](boost::system::error_code /*e*/, std::size_t /*bytes_sent*/) {});
        }
    }

private:
    void receivePacket() {
        socket_.async_receive_from(
            boost::asio::buffer(data_, max_length),
            remote_endpoint_,
            [this](boost::system::error_code ec, std::size_t length) {
                if (!ec && length > 0) {
                    processPacket(length);
                }
                receivePacket();
            });
    }

    void processPacket(std::size_t length) {
        std::lock_guard<std::mutex> lock(playerMutex_);
        std::string receivedData(data_, length);
        // Parse packet and update player state
        size_t pos = receivedData.find("ID:");
        if (pos != std::string::npos) {
            std::string id = receivedData.substr(pos + 3, receivedData.find(' ', pos) - (pos + 3));
            PlayerState& player = players_[id];
            player.id = id;
            player.isShooting = receivedData.find("Shooting") != std::string::npos;

            pos = receivedData.find("Pos:");
            if (pos != std::string::npos) {
                pos += 4; // Move past "Pos:"
                size_t endX = receivedData.find(',', pos);
                size_t endY = receivedData.find(',', endX + 1);
                size_t endZ = receivedData.find(')', endY + 1);

                player.x = std::stof(receivedData.substr(pos, endX - pos));
                player.y = std::stof(receivedData.substr(endX + 1, endY - (endX + 1)));
                player.z = std::stof(receivedData.substr(endY + 1, endZ - (endY + 1)));
            }
        }
    }

    udp::socket socket_;
    udp::endpoint remote_endpoint_;
    enum { max_length = 1024 };
    char data_[max_length];
    std::unordered_map<std::string, PlayerState> players_;
    std::mutex playerMutex_;
};

int main(int argc, char* argv[]) {
    try {
        if (argc != 2) {
            std::cerr << "Usage: ./udp_server <port>\n";
            return 1;
        }

        boost::asio::io_context io_context;

        GameServer server(io_context, std::atoi(argv[1]));

        // Start sending player states every second
        auto sendStates = [&server]() {
            while (true) {
                std::this_thread::sleep_for(std::chrono::seconds(1));
                server.sendPlayerStates();
            }
        };

        std::thread thread(sendStates);

        io_context.run();

        thread.join();
    } catch (std::exception& e) {
        std::cerr << "Exception: " << e.what() << "\n";
    }

    return 0;
}